SELECT area_de_atuacao FROM (SELECT ch.area_ingresso AS area_de_atuacao, COUNT(*) AS quantidade_participacoes FROM calc_hora_aula_media ch JOIN curso c ON LOWER(ch.sigla_curso) = LOWER(c.sigla) WHERE LOWER(ch.sigla_campus) = LOWER('goi') AND LOWER(c.nivel) = LOWER('ensino medio') AND LOWER(c.modalidade) LIKE LOWER('%integrado%') AND ch.ano >= CAST(strftime('%Y', 'now') AS INTEGER) - 5 GROUP BY ch.area_ingresso ORDER BY quantidade_participacoes DESC LIMIT 1) AS t;